1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: Customer; steps: Step[] };
9	type Policy = { items: Item[]; remainingCap: number };
10	
11	const PROCESSING_FEE = 5;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
15	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
16	
17	const INSURANCE_VALUE: Record<string, number> = {
18	  sword: 1000,
19	  amulet: 600,
20	  staff: 800,
21	  potion: 400,
22	  rune: 250,
23	  moonstone: 250,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_THRESHOLD_YEARS = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PRICE = 60;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const BASE_PREMIUM: Record<string, number> = {
39	  sword: 100,
40	  amulet: 60,
41	  staff: 80,
42	  potion: 40,
43	  rune: 25,
44	  moonstone: 25,
45	};
46	
47	const countByType = (items: Item[]): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
50	  return counts;
51	};
52	
53	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
54	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
55	
56	const lineItemPrice = (type: string, count: number): number =>
57	  qualifiesForComponentBlock(type, count)
58	    ? COMPONENT_BLOCK_PRICE
59	    : BASE_PREMIUM[type] * count;
60	
61	const sumBasePremiums = (items: Item[]): number =>
62	  Object.entries(countByType(items))
63	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
64	
65	const rateOf = (amount: number, rate: number, applies: boolean): number =>
66	  applies ? amount * rate : 0;
67	
68	const isCursed = (item: Item): boolean => item.cursed === true;
69	
70	const isHighlyEnchanted = (item: Item): boolean =>
71	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	
73	const itemSurcharges = (items: Item[]): number =>
74	  items.reduce((sum, item) => {
75	    const base = BASE_PREMIUM[item.type];
76	    return sum
77	      + rateOf(base, CURSE_SURCHARGE_RATE, isCursed(item))
78	      + rateOf(base, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted(item));
79	  }, 0);
80	
81	const isLoyalCustomer = (customer: Customer): boolean =>
82	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
83	
84	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
85	
86	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
87	  const basePremium = sumBasePremiums(items);
88	  const surcharges = itemSurcharges(items);
89	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
90	  const loyaltyDiscount = rateOf(basePremium, LOYALTY_DISCOUNT_RATE, isLoyalCustomer(customer));
91	  const followupDiscount = rateOf(basePremium, FOLLOWUP_DISCOUNT_RATE, isFollowupContract(stepIndex));
92	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
93	};
94	
95	const validateItems = (items: Item[]): void => {
96	  for (const item of items) {
97	    if (!(item.type in BASE_PREMIUM)) {
98	      throw new Error(`Unknown item type: ${item.type}`);
99	    }
100	  }
101	};
102	
103	const insuranceSum = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
105	
106	const reimbursableAmount = (item: Item, amount: number): number =>
107	  (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD
108	    ? amount * CLAIM_HIGH_ENCHANTMENT_RATE
109	    : amount;
110	
111	const damagePayout = (damage: Damage, policy: Policy): number => {
112	  const item = policy.items.find((i) => i.type === damage.itemType)!;
113	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
114	};
115	
116	const totalPayout = (incident: Incident, policy: Policy): number =>
117	  incident.damages.reduce((sum, dmg) => sum + damagePayout(dmg, policy), 0);
118	
119	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
120	  const payout = totalPayout(incident, policy);
121	  policy.remainingCap -= payout;
122	  return { payout, remainingCap: policy.remainingCap };
123	};
124	
125	const processQuote = (step: QuoteStep, customer: Customer, stepIndex: number): { policy: Policy; premium: number } => {
126	  validateItems(step.items);
127	  const policy: Policy = { items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER };
128	  return { policy, premium: quotePremium(step.items, customer, stepIndex) };
129	};
130	
131	export const runScenario = (input: unknown): unknown => {
132	  const scenario = input as Scenario;
133	  const policies: Policy[] = [];
134	  const results = scenario.steps.map((step, index) => {
135	    if (step.op === "quote") {
136	      const { policy, premium } = processQuote(step, scenario.customer, index);
137	      policies[index] = policy;
138	      return { premium };
139	    }
140	    return processClaim(policies[step.policy], step.incident);
141	  });
142	  return { results };
143	};
